        attempt (sharpAlterationRef |>> AlterationNode.SharpAlteration)
        attempt (flatAlterationRef |>> AlterationNode.FlatAlteration) ]

do alterationRefImpl.Value <- alterationParser

let private sharpAlterationParser : Parser<SharpAlterationNode, unit> =
    pipe2
        (pstring "#")
        (alterationDegreeRef)
        (fun v0 v1 -> SharpAlterationNode.SharpAlteration (v0, v1))
do sharpAlterationRefImpl.Value <- sharpAlterationParser

let private flatAlterationParser : Parser<FlatAlterationNode, unit> =
    pipe2
        (pstring "b")
        (alterationDegreeRef)
        (fun v0 v1 -> FlatAlterationNode.FlatAlteration (v0, v1))
do flatAlterationRefImpl.Value <- flatAlterationParser

let private alterationDegreeParser : Parser<AlterationDegreeNode, unit> =
    choice [
        attempt (pstring "5" >>% AlterationDegreeNode.N5)
        attempt (pstring "9" >>% AlterationDegreeNode.N9)
        attempt (pstring "11" >>% AlterationDegreeNode.N11)
        attempt (pstring "13" >>% AlterationDegreeNode.N13) ]

do alterationDegreeRefImpl.Value <- alterationDegreeParser

let private bassNoteParser : Parser<BassNoteNode, unit> =
    pipe3
        (pstring "/")
        (noteRef)
        (opt (accidentalRef))
        (fun v0 v1 v2 -> BassNoteNode.BassNote (v0, v1, v2))
do bassNoteRefImpl.Value <- bassNoteParser

let private separatorParser : Parser<SeparatorNode, unit> =
    choice [
        attempt (dashSeparatorRef |>> SeparatorNode.DashSeparator)
        attempt (arrowSeparatorRef |>> SeparatorNode.ArrowSeparator)
        attempt (spaceSeparatorRef |>> SeparatorNode.SpaceSeparator)
        attempt (commaSeparatorRef |>> SeparatorNode.CommaSeparator) ]

do separatorRefImpl.Value <- separatorParser

let private dashSeparatorParser : Parser<DashSeparatorNode, unit> =
    pstring "-" |>> DashSeparatorNode.DashSeparator

do dashSeparatorRefImpl.Value <- dashSeparatorParser

let private arrowSeparatorParser : Parser<ArrowSeparatorNode, unit> =
    choice [
        attempt (pstring "->" >>% ArrowSeparatorNode.DashGt)
        attempt (pstring "→" >>% ArrowSeparatorNode.Arrow) ]

do arrowSeparatorRefImpl.Value <- arrowSeparatorParser

let private spaceSeparatorParser : Parser<SpaceSeparatorNode, unit> =
    whitespaceRef |>> SpaceSeparatorNode.SpaceSeparator

do spaceSeparatorRefImpl.Value <- spaceSeparatorParser

let private commaSeparatorParser : Parser<CommaSeparatorNode, unit> =
    pstring "," |>> CommaSeparatorNode.CommaSeparator

do commaSeparatorRefImpl.Value <- commaSeparatorParser

let private stringLiteralParser : Parser<StringLiteralNode, unit> =
    pipe3
        (pstring "\"")
        (many (characterRef))
        (pstring "\"")
        (fun v0 v1 v2 -> StringLiteralNode.StringLiteral (v0, v1, v2))
do stringLiteralRefImpl.Value <- stringLiteralParser

let private numberParser : Parser<NumberNode, unit> =
    pipe2
        (digitRef)
        (many (digitRef))
        (fun v0 v1 -> NumberNode.Number (v0, v1))
do numberRefImpl.Value <- numberParser

let private digitParser : Parser<DigitNode, unit> =
    choice [
        attempt (pstring "0" >>% DigitNode.N0)
        attempt (pstring "1" >>% DigitNode.N1)
        attempt (pstring "2" >>% DigitNode.N2)
        attempt (pstring "3" >>% DigitNode.N3)
        attempt (pstring "4" >>% DigitNode.N4)
        attempt (pstring "5" >>% DigitNode.N5)
        attempt (pstring "6" >>% DigitNode.N6)
        attempt (pstring "7" >>% DigitNode.N7)
        attempt (pstring "8" >>% DigitNode.N8)
        attempt (pstring "9" >>% DigitNode.N9) ]

do digitRefImpl.Value <- digitParser

let private whitespaceParser : Parser<WhitespaceNode, unit> =
    choice [
        attempt (pstring " " >>% WhitespaceNode.Empty)
        attempt (pstring "\\t" >>% WhitespaceNode.U005Ct)
        attempt (pstring "\\n" >>% WhitespaceNode.U005Cn)
        attempt (pstring "\\r" >>% WhitespaceNode.U005Cr) ]

do whitespaceRefImpl.Value <- whitespaceParser

let private characterParser : Parser<CharacterNode, unit> =
    choice [
        attempt (letterRef |>> CharacterNode.Letter)
        attempt (digitRef |>> CharacterNode.Digit)
        attempt (symbolRef |>> CharacterNode.Symbol) ]

do characterRefImpl.Value <- characterParser

let private letterParser : Parser<LetterNode, unit> =
