        attempt (pstring "A" >>% LetterNode.A1)
        attempt (pstring "B" >>% LetterNode.B1)
        attempt (pstring "C" >>% LetterNode.C1)
        attempt (pstring "D" >>% LetterNode.D1)
        attempt (pstring "E" >>% LetterNode.E1)
        attempt (pstring "F" >>% LetterNode.F1)
