        attempt (pstring "J" >>% LetterNode.J1)
        attempt (pstring "K" >>% LetterNode.K1)
        attempt (pstring "L" >>% LetterNode.L1)
        attempt (pstring "M" >>% LetterNode.M1)
        attempt (pstring "N" >>% LetterNode.N1)
        attempt (pstring "O" >>% LetterNode.O1)
        attempt (pstring "P" >>% LetterNode.P1)
        attempt (pstring "Q" >>% LetterNode.Q1)
        attempt (pstring "R" >>% LetterNode.R1)
        attempt (pstring "S" >>% LetterNode.S1)
        attempt (pstring "T" >>% LetterNode.T1)
        attempt (pstring "U" >>% LetterNode.U1)
        attempt (pstring "V" >>% LetterNode.V1)
        attempt (pstring "W" >>% LetterNode.W1)
        attempt (pstring "X" >>% LetterNode.X1)
        attempt (pstring "Y" >>% LetterNode.Y1)
        attempt (pstring "Z" >>% LetterNode.Z1)
        attempt (pstring "a" >>% LetterNode.A2)
        attempt (pstring "b" >>% LetterNode.B2)
        attempt (pstring "c" >>% LetterNode.C2)
        attempt (pstring "d" >>% LetterNode.D2)
        attempt (pstring "e" >>% LetterNode.E2)
        attempt (pstring "f" >>% LetterNode.F2)
        attempt (pstring "g" >>% LetterNode.G2)
        attempt (pstring "h" >>% LetterNode.H2)
        attempt (pstring "i" >>% LetterNode.I2)
        attempt (pstring "j" >>% LetterNode.J2)
        attempt (pstring "k" >>% LetterNode.K2)
        attempt (pstring "l" >>% LetterNode.L2)
        attempt (pstring "m" >>% LetterNode.M2)
        attempt (pstring "n" >>% LetterNode.N2)
        attempt (pstring "o" >>% LetterNode.O2)
        attempt (pstring "p" >>% LetterNode.P2)
        attempt (pstring "q" >>% LetterNode.Q2)
        attempt (pstring "r" >>% LetterNode.R2)
        attempt (pstring "s" >>% LetterNode.S2)
        attempt (pstring "t" >>% LetterNode.T2)
        attempt (pstring "u" >>% LetterNode.U2)
        attempt (pstring "v" >>% LetterNode.V2)
        attempt (pstring "w" >>% LetterNode.W2)
        attempt (pstring "x" >>% LetterNode.X2)
        attempt (pstring "y" >>% LetterNode.Y2)
        attempt (pstring "z" >>% LetterNode.Z2) ]

do letterRefImpl.Value <- letterParser

let private symbolParser : Parser<SymbolNode, unit> =
    choice [
        attempt (pstring "!" >>% SymbolNode.Bang)
        attempt (pstring "@" >>% SymbolNode.At)
        attempt (pstring "#" >>% SymbolNode.Sharp)
        attempt (pstring "$" >>% SymbolNode.Dollar)
        attempt (pstring "%" >>% SymbolNode.Percent)
        attempt (pstring "^" >>% SymbolNode.Caret)
        attempt (pstring "&" >>% SymbolNode.Amp)
        attempt (pstring "*" >>% SymbolNode.Star)
        attempt (pstring "(" >>% SymbolNode.LParen)
        attempt (pstring ")" >>% SymbolNode.RParen)
        attempt (pstring "_" >>% SymbolNode.Under)
        attempt (pstring "+" >>% SymbolNode.Plus)
        attempt (pstring "=" >>% SymbolNode.Eq)
        attempt (pstring "{" >>% SymbolNode.U007B)
        attempt (pstring "}" >>% SymbolNode.U007D)
        attempt (pstring "[" >>% SymbolNode.U005B)
        attempt (pstring "]" >>% SymbolNode.U005D)
        attempt (pstring "|" >>% SymbolNode.U007C)
        attempt (pstring "\\" >>% SymbolNode.U005C)
        attempt (pstring ":" >>% SymbolNode.Colon)
        attempt (pstring ";" >>% SymbolNode.U003B)
        attempt (pstring "'" >>% SymbolNode.U0027)
        attempt (pstring "<" >>% SymbolNode.Lt)
        attempt (pstring ">" >>% SymbolNode.Gt)
        attempt (pstring "?" >>% SymbolNode.U003F)
        attempt (pstring "/" >>% SymbolNode.Slash)
        attempt (pstring "." >>% SymbolNode.Dot)
        attempt (pstring "," >>% SymbolNode.U002C)
        attempt (pstring "-" >>% SymbolNode.Dash) ]

do symbolRefImpl.Value <- symbolParser

/// Parse ChordProgression from a string. Returns Ok or Error.
let parse (input: string) : Result<ProgressionNode, string> =
    match run (progressionParser .>> eof) input with
    | Success (v, _, _) -> Result.Ok v
    | Failure (msg, _, _) -> Result.Error msg
